  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    return `Não consegui silenciar: ${msg}`;
  }
}

async function executeRestartSelf(message: Message, action: Extract<FwpAction, { type: "restart_self" }>): Promise<string> {
