    const file = require('node:fs').createWriteStream(jarPath);
    http.get(JAR_URL, (response) => {
      response.pipe(file);
      file.on('finish', () => {
        file.close();
        resolve(true);
      });
    }).on('error', (err) => reject(err));
  });
}

